// validateListValue validates array values for $in/$nin operators.
func (qb *QueryBuilder) validateListValue(fieldName string, value interface{}) (interface{}, error) {
	slice, ok := value.([]interface{})
	if !ok {
		return nil, fmt.Errorf("value for in/nin operator must be an array")
	}
	if len(slice) == 0 {
		return nil, fmt.Errorf("array for in/nin must not be empty")
	}
	if len(slice) > 100 {
		return nil, fmt.Errorf("array for in/nin exceeds maximum length of 100")
	}

	fieldDef := qb.allowedFields[fieldName]
	if fieldDef.ValueValidator == nil {
		return nil, fmt.Errorf("field %q has no value validator", fieldName)
	}

	validatedSlice := make(bson.A, 0, len(slice))
	for i, item := range slice {
		validated, err := fieldDef.ValueValidator(item)
		if err != nil {
			return nil, fmt.Errorf("array element %d: %w", i, err)
		}
		validatedSlice = append(validatedSlice, validated)
	}

	return validatedSlice, nil
}

// AllowedSortField defines a field that can be used for sorting.
type AllowedSortField struct {
	BSONName string
}

// SortCondition represents a user-provided sort instruction.
type SortCondition struct {
	Field     string `json:"field"`
	Direction string `json:"direction"` // "asc" or "desc"
}

// BuildSort constructs a safe MongoDB sort document from validated user input.
func BuildSort(conditions []SortCondition, allowedSortFields map[string]AllowedSortField) (bson.D, error) {
	if len(conditions) == 0 {
		return bson.D{}, nil
	}
	if len(conditions) > 5 {
		return nil, errors.New("too many sort conditions (maximum 5)")
	}

	sort := bson.D{}
	for i, cond := range conditions {
		fieldDef, ok := allowedSortFields[cond.Field]
		if !ok {
			return nil, fmt.Errorf("sort condition %d: field %q is not allowed for sorting", i, cond.Field)
		}

		dir := strings.ToLower(strings.TrimSpace(cond.Direction))
		var sortDir int
		switch dir {
		case "asc", "1":
			sortDir = 1
		case "desc", "-1":
			sortDir = -1
		default:
			return nil, fmt.Errorf("sort condition %d: direction must be 'asc' or 'desc'", i)
		}

		sort = append(sort, bson.E{Key: fieldDef.BSONName, Value: sortDir})
	}

	return sort, nil
}

// AllowedProjectionField defines a field that can be included in projections.
type AllowedProjectionField struct {
	BSONName string
}

// BuildProjection constructs a safe MongoDB projection from validated user input.
func BuildProjection(requestedFields []string, allowedProjectionFields map[string]AllowedProjectionField) (bson.M, error) {
	if len(requestedFields) == 0 {
		return nil, nil // No projection, return all fields
	}
	if len(requestedFields) > 50 {
		return nil, errors.New("too many projection fields (maximum 50)")
	}

	projection := bson.M{}
	for i, field := range requestedFields {
		fieldDef, ok := allowedProjectionFields[field]
		if !ok {
			return nil, fmt.Errorf("projection field %d: %q is not allowed", i, field)
		}
		projection[fieldDef.BSONName] = 1
	}

	return projection, nil
}

// SecureFind performs a safe MongoDB find with validated filters, sort, and projection.
func SecureFind(
	ctx context.Context,
	collection *mongo.Collection,
	qb *QueryBuilder,
	conditions []FilterCondition,
	sortConditions []SortCondition,
	allowedSortFields map[string]AllowedSortField,
	projectionFields []string,
	allowedProjectionFields map[string]AllowedProjectionField,
	limit int64,
	skip int64,
) ([]bson.M, error) {
	// Validate and build the query filter
	filter, err := qb.BuildQuery(conditions)
	if err != nil {
		return nil, fmt.Errorf("invalid filter: %w", err)
	}

	// Build find options
	opts := options.Find()

	// Validate and set sort
	if len(sortConditions) > 0 {
		sort, err := BuildSort(sortConditions, allowedSortFields)
		if err != nil {
			return nil, fmt.Errorf("invalid sort: %w", err)
		}
		opts.SetSort(sort)
	}

	// Validate and set projection
	if len(projectionFields) > 0 {
		projection, err := BuildProjection(projectionFields, allowedProjectionFields)
		if err != nil {
			return nil, fmt.Errorf("invalid projection: %w", err)
		}
		opts.SetProjection(projection)
	}

	// Enforce safe limits
	if limit <= 0 || limit > 1000 {
		limit = 100 // Default safe limit
	}
	opts.SetLimit(limit)

	if skip < 0 {
		skip = 0
	}
	if skip > 100000 {
		return nil, errors.New("skip value too large")
	}
	opts.SetSkip(skip)

	// Execute the query
	cursor, err := collection.Find(ctx, filter, opts)
	if err != nil {
		return nil, fmt.Errorf("query execution failed: %w", err)
	}
	defer cursor.Close(ctx)

	var results []bson.M
	if err := cursor.All(ctx, &results); err != nil {
		return nil, fmt.Errorf("failed to decode results: %w", err)
	}

	return results, nil
}

